import React from 'react';
import {
  Autocomplete,
  Button,
  FormControl,
  InputLabel,
  MenuItem,
  Select,
  TextField,
} from '@mui/material';
import DatePicker from '@mui/lab/DatePicker';
import LocalizationProvider from '@mui/lab/LocalizationProvider';
import AdapterDateFns from '@mui/lab/AdapterDateFns';
import { createFilterOptions } from '@mui/material/Autocomplete';
export default function ExpensesApplyForm({
  expenses,
  control,
  Controller,
  date,
  setDate,
  projects,
  projectSelect,
  setProjectSelect,
  setValue,
  setBudgetSelect,
  bank,
  setBank,
  customer,
  onAddCustomer,
}) {
  const filter = createFilterOptions();

  const thaiBanks = [
    'Promptpay',
    'Kasikornbank(KBank)',
    'Government Savings Bank(GSB)',
    'Krungthai Bank(KTB)',
    'Siam Commercial Bank(SCB)',
    'Bangkok Bank(BBL)',
    'Bank of Ayudhya(BAY)',
    'TMBThanachart Bank(TTB)',
    'CIMB Thai Bank(CIMBT)',
    'United Overseas Bank(UOB)',
    'Kiatnakin Phatra Bank(KKP)',
    'Land and Houses Bank(LH Bank)',
    'Citibank N.A.',
  ];
  const handleChange = (event) => {
    setBank(event.target.value);
  };

  const handleCheckLevel = (data, index) => {
    const each = _.find(projects.rows, { _id: data?._id });
    setValue(`project`, each?._id);
    setProjectSelect(each);
  };

  const handleCheckBudget = (data, index) => {
    const each = _.find(projectSelect?.budget, { _id: data?._id });
    setValue(`budget`, each?._id);
    setBudgetSelect(each);
  };

  const handleAdd = (inputValue, fieldName) => {
    if (onAddCustomer && inputValue) {
      onAddCustomer(inputValue, fieldName);
    }
  };

  const handleCheckPayee = (data, index) => {
    const each = _.find(customer?.rows, { _id: data?._id });
    setValue(`customer`, each?._id);
    setValue(`payee.bank`, each?.bank?.bank_name);
    setValue(`payee.name`, each?.bank?.account_name);
    setValue(`payee.account_number`, each?.bank?.account_number);
  };

  return (
    <div>
      <div className="lg:grid grid-cols-2 gap-2">
        <div className="w-full px-1 py-1">
          <LocalizationProvider dateAdapter={AdapterDateFns}>
            <DatePicker
              label="วันที่ขอเบิก"
              value={date}
              onChange={(newValue) => {
                setDate(newValue);
              }}
              renderInput={(params) => (
                <TextField {...params} size="small" fullWidth />
              )}
            />
          </LocalizationProvider>
        </div>
        <div className="w-full px-1 py-1">
          <Controller
            name={`project`}
            control={control}
            render={({ field }) => (
              <Autocomplete
                {...field}
                disablePortal
                id="free-solo-demo"
                freeSolo
                required
                options={projects?.rows || []}
                getOptionLabel={(option) =>
                  `${option.project_number} | ${option.name}`
                }
                onChange={(e, newValue) => handleCheckLevel(newValue)}
                renderInput={(params) => (
                  <TextField
                    {...field}
                    {...params}
                    size="small"
                    label="Project"
                    required
                  />
                )}
              />
            )}
          />{' '}
        </div>
        <div className="w-full px-1 py-1">
          <Controller
            name={`budget`}
            control={control}
            render={({ field }) => (
              <Autocomplete
                {...field}
                disablePortal
                id="free-solo-demo"
                freeSolo
                required
                options={projectSelect?.budget || []}
                getOptionLabel={(option) =>
                  `${option.prefix || ''}${option.budget_number} | ${
                    option.name
                  }`
                }
                onChange={(e, newValue) => handleCheckBudget(newValue)}
                renderInput={(params) => (
                  <TextField
                    {...field}
                    {...params}
                    size="small"
                    label="Budget"
                    required
                  />
                )}
              />
            )}
          />{' '}
        </div>
        <div className="w-full px-1 py-1">
          <Controller
            name={'invoice_number'}
            control={control}
            defaultValue={''}
            render={({ field }) => (
              <TextField
                {...field}
                label="invoice number"
                fullWidth
                size={'small'}
              />
            )}
          />
        </div>

        <div className="w-full px-1 py-1">
          <Controller
            name={'name'}
            control={control}
            defaultValue={expenses ? expenses?.name : ''}
            rules={{
              required: true,
              maxLength: {
                value: 255,
                message: 'รายการต้องไม่เกิน 255 ตัวอักษร',
              },
            }}
            render={({ field, fieldState: { error } }) => (
              <TextField
                {...field}
                label="รายการ"
                fullWidth
                size={'small'}
                required
                inputProps={{ maxLength: 255 }}
                error={!!error}
                helperText={
                  error
                    ? error.message
                    : `${field.value?.length || 0}/255 ตัวอักษร`
                }
              />
            )}
          />
        </div>
        <div className="w-full px-1 py-1">
          <Controller
            name={'price'}
            control={control}
            defaultValue={expenses ? expenses?.price : ''}
            rules={{ required: true }}
            render={({ field }) => (
              <TextField
                {...field}
                label="ราคา"
                fullWidth
                type="number"
                size={'small'}
                required
              />
            )}
          />
        </div>
      </div>
      <div className="w-full px-1 py-1">ผู้รับเงิน</div>
      <div className="lg:grid grid-cols-2 gap-2">
        <div className="w-full py-1">
          <Controller
            name={`customer`}
            control={control}
            render={({ field }) => (
              <Autocomplete
                {...field}
                freeSolo
                disablePortal
                options={customer?.rows || []}
                getOptionLabel={(option) => `${option?.name}`}
                filterOptions={(options, params) => {
                  const filtered = filter(options, params);
                  const { inputValue } = params;
                  const isExisting = options.some(
                    (option) =>
                      `${option?.name}`.toLowerCase() ===
                      inputValue.toLowerCase(),
                  );
                  if (inputValue !== '' && !isExisting) {
                    filtered.push({
                      inputValue,
                      firstname: inputValue,
                      lastname: '',
                      isAddNew: true,
                    });
                  }
                  return filtered;
                }}
                onChange={(e, newValue) => {
                  if (typeof newValue === 'string') {
                    handleAdd(newValue, 'bank');
                  } else if (newValue && newValue.isAddNew) {
                    handleAdd(newValue?.inputValue, 'bank');
                  } else {
                    handleCheckPayee(newValue);
                  }
                }}
                renderOption={(props, option) =>
                  option.isAddNew ? (
                    <li {...props}>
                      <Button
                        color="primary"
                        size="small"
                        onMouseDown={(e) => e.preventDefault()}
                        sx={{ minWidth: 0, p: 0, mr: 1 }}
                      >
                        Add
                      </Button>
                      "{option?.inputValue}"
                    </li>
                  ) : (
                    <li {...props}>{option?.name}</li>
                  )
                }
                renderInput={(params) => (
                  <TextField
                    {...field}
                    {...params}
                    size="small"
                    label="Payee"
                    //required
                  />
                )}
              />
            )}
          />
        </div>
        <div className="py-1">
          <Controller
            name={'payee.bank'}
            control={control}
            defaultValue={''}
            //rules={{ //required: true }}
            render={({ field }) => (
              <TextField
                {...field}
                defaultValue={''}
                label="Bank Name"
                fullWidth
                size={'small'}
                //required
              />
            )}
          />
        </div>
        <div className="py-1">
          <Controller
            name={'payee.name'}
            control={control}
            defaultValue={''}
            render={({ field }) => (
              <TextField
                {...field}
                label="Account Name"
                defaultValue={''}
                fullWidth
                size={'small'}
                //required
              />
            )}
          />
        </div>
        <div className="py-1">
          <Controller
            name={'payee.account_number'}
            defaultValue={''}
            control={control}
            render={({ field }) => (
              <TextField
                {...field}
                label="Account Number"
                fullWidth
                size={'small'}
                //required
              />
            )}
          />
        </div>
      </div>

      <div className="flex justify-center">
        <Button variant="contained" type="submit">
          บันทึก
        </Button>
      </div>
    </div>
  );
}
