import React, { useState, useEffect } from 'react';
import {
  TextField,
  Button,
  Card,
  Box,
  IconButton,
  Typography,
  Container,
  Paper,
  Divider,
  Avatar,
  Fade,
  Stack,
} from '@mui/material';
import { Scanner } from '@yudiel/react-qr-scanner';
import { useDispatch, useSelector } from 'react-redux';
import _ from 'lodash';
import * as actions from '../../redux/actions';
import { useParams } from 'react-router-dom/cjs/react-router-dom.min';
import CloseIcon from '@mui/icons-material/Close';
import ClearIcon from '@mui/icons-material/Clear';
import AccessTimeIcon from '@mui/icons-material/AccessTime';
import QrCodeScannerIcon from '@mui/icons-material/QrCodeScanner';
import PersonIcon from '@mui/icons-material/Person';
import GroupsIcon from '@mui/icons-material/Groups';
import PlaceIcon from '@mui/icons-material/Place';
import Cameras from 'components/Camera/Cameras';
import Loading from 'components/Loading';
import CameraIcon from '@mui/icons-material/CameraAlt';
import SaveIcon from '@mui/icons-material/Save';
import { useGeolocated } from 'react-geolocated';
import CalculateGps from 'utils/functions/CalculateGps';
import CalculateGpsByProject from 'utils/functions/CalculateGpsByProject';

export default function ManpowerCheckin() {
  const dispatch = useDispatch();
  const { id } = useParams();
  const employee = useSelector((state) => state.employee);
  const project = useSelector((state) => state.project);
  const [currentTime, setCurrentTime] = useState(
    new Date().toLocaleTimeString(),
  );
  const [openScan, setOpenScan] = useState(true);
  const [imgSrc, setImgSrc] = useState(null);
  const [loading, setLoading] = useState(false);
  const [emSelect, setEmSelect] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [scannerReady, setScannerReady] = useState(false);

  const {
    coords,
    isGeolocationAvailable,
    isGeolocationEnabled,
  } = useGeolocated({
    positionOptions: {
      enableHighAccuracy: false,
    },
    userDecisionTimeout: 5000,
  });

  const locationCheckIn = CalculateGpsByProject(coords, project, 1000);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date().toLocaleTimeString());
    }, 1000);

    // ให้เวลา scanner เตรียมพร้อม
    const scannerTimer = setTimeout(() => {
      setScannerReady(true);
    }, 1000);

    return () => {
      clearInterval(timer);
      clearTimeout(scannerTimer);
    };
  }, []);

  useEffect(() => {
    dispatch(actions.projectGet(id));
  }, [dispatch, id]);

  const handleScan = async (data) => {
    if (data) {
      await dispatch(actions.employeeTimestamp({ em: data }));
      setOpenScan(false);
    }
  };

  const handleRescan = async () => {
    await dispatch(actions.employeeReset());
    setOpenScan(true);
    setShowCamera(false);
    setImgSrc(null);
  };

  const handleButtonClick = () => {
    if (_.isEmpty(emSelect)) {
      alert('กรุณากรอกรหัสพนักงาน');
    } else {
      dispatch(actions.employeeTimestamp({ em: emSelect }));
      setOpenScan(false);
    }
  };

  const onSubmit = async (data) => {
    if (!imgSrc) {
      alert('กรุณาถ่ายรูปก่อนบันทึก');
    } else {
      const confirm = window.confirm('ยืนยันการบันทึกข้อมูล?');
      if (confirm) {
        setLoading(true);
        const dataSubmit = {
          employee: data?._id,
          employeekey: data?.check_key,
          employee_firstname: data?.firstname,
          employee_lastname: data?.lastname,
          employeeType: data?.type,
          salary: data?.salary,
          salary_extra: data?.salary_extra,
          status_checkIn: true,
          project_in: project,
          image: imgSrc,
        };
        await dispatch(actions.timestampCreate(dataSubmit));
        setLoading(false);
        setImgSrc(null);
        handleRescan();
      }
    }
  };

  const handleChange = (event) => {
    setEmSelect(event.target.value);
  };

  const QRReader = () => (
    <Box className="flex justify-center my-4">
      <Paper
        elevation={3}
        sx={{
          p: 1,
          borderRadius: 2,
          width: { xs: 280, sm: 320 },
          overflow: 'hidden',
        }}
      >
        <Fade in={scannerReady}>
          <Box>
            {scannerReady && (
              <Scanner
                onScan={(results) => {
                  handleScan(results?.[0]?.rawValue);
                }}
                allowMultiple
                containerStyle={{
                  width: '100%',
                  height: '100%',
                  paddingTop: '5px',
                }}
              />
            )}
          </Box>
        </Fade>
      </Paper>
    </Box>
  );

  const renderCameraButton = () => (
    <Box className="flex justify-center my-4">
      <Button
        variant="contained"
        size="large"
        startIcon={<CameraIcon />}
        onClick={() => setShowCamera(true)}
        sx={{
          borderRadius: 3,
          py: 1.5,
          px: 3,
          boxShadow: 3,
          background: 'linear-gradient(45deg, #2196F3 30%, #21CBF3 90%)',
        }}
      >
        เปิดกล้องถ่ายรูป
      </Button>
    </Box>
  );

  const renderImage = () => (
    <Box>
      {!showCamera ? (
        renderCameraButton()
      ) : (
        <Paper
          elevation={2}
          sx={{ borderRadius: 2, overflow: 'hidden', mb: 2 }}
        >
          <Box className="flex justify-center">
            <Cameras imgSrc={imgSrc} setImgSrc={setImgSrc} />
          </Box>
        </Paper>
      )}
    </Box>
  );

  const renderFormEmployee = () => (
    <Container maxWidth="sm" sx={{ py: 4 }}>
      <Paper
        elevation={4}
        sx={{
          p: 3,
          borderRadius: 4,
          background: 'linear-gradient(to bottom, #ffffff, #f5f8ff)',
          boxShadow: '0 8px 24px rgba(149, 157, 165, 0.2)',
        }}
      >
        <Typography
          variant="h4"
          className="font-bold text-center mb-2"
          sx={{ color: '#1976d2' }}
        >
          ลงเวลาเข้างาน
        </Typography>

        <Divider sx={{ mb: 2 }} />

        <Box className="flex justify-center items-center mb-3">
          <Avatar
            sx={{
              bgcolor: '#e3f2fd',
              width: 56,
              height: 56,
              mb: 1,
            }}
          >
            <AccessTimeIcon fontSize="large" color="primary" />
          </Avatar>
        </Box>

        <Typography
          variant="h6"
          className="text-center mb-1"
          sx={{ color: '#1976d2' }}
        >
          โครงการ {project?.name}
        </Typography>
        <Box>
          <Stack direction="row" spacing={1} alignItems="flex-start">
            <PlaceIcon fontSize="small" color="error" sx={{ mt: 0.5 }} />
            <Box>
              <Typography variant="body2" fontWeight={500}>
                {locationCheckIn?.nearestProject?.project?.name ||
                  'ไม่พบโครงการในบริเวณนี้'}
              </Typography>
              <Typography variant="caption" color="text.secondary">
                ระยะห่าง:{' '}
                {locationCheckIn?.nearestProject?.distanceText || 'ไม่พบข้อมูล'}
              </Typography>
            </Box>
          </Stack>
        </Box>

        <Typography
          variant="h5"
          className="text-center mb-4 font-bold"
          sx={{ color: '#333' }}
        >
          {currentTime}
        </Typography>

        {openScan && (
          <Fade in={true}>
            <Box>
              <Box className="flex justify-center items-center my-2">
                <QrCodeScannerIcon color="primary" sx={{ mr: 1 }} />
                <Typography variant="h6">สแกน QR code</Typography>
              </Box>

              {QRReader()}

              <Box sx={{ mt: 3 }}>
                <Paper elevation={1} sx={{ p: 2, borderRadius: 2 }}>
                  <Typography variant="subtitle1" sx={{ mb: 1 }}>
                    หรือค้นหาด้วยรหัสพนักงาน
                  </Typography>
                  <Box className="flex gap-2">
                    <TextField
                      variant="outlined"
                      label="ชื่อ/รหัสพนักงาน"
                      size="small"
                      onChange={handleChange}
                      fullWidth
                      sx={{ '& .MuiOutlinedInput-root': { borderRadius: 2 } }}
                    />
                    <Button
                      variant="contained"
                      onClick={handleButtonClick}
                      sx={{ borderRadius: 2 }}
                    >
                      ค้นหา
                    </Button>
                  </Box>
                </Paper>
              </Box>
            </Box>
          </Fade>
        )}
      </Paper>
    </Container>
  );

  const renderEmployeeList = () => (
    <Container maxWidth="sm" sx={{ mb: 4 }}>
      {_.isEmpty(employee?.rows)
        ? !openScan && (
            <Paper
              elevation={2}
              sx={{
                p: 3,
                borderRadius: 4,
                textAlign: 'center',
                bgcolor: '#f9f9f9',
              }}
            >
              <Typography variant="body1" color="textSecondary" sx={{ mb: 2 }}>
                ไม่มีข้อมูลพนักงาน
              </Typography>
              <IconButton
                onClick={handleRescan}
                sx={{
                  color: '#f44336',
                  bgcolor: '#ffebee',
                  '&:hover': { bgcolor: '#ffcdd2' },
                }}
              >
                <ClearIcon fontSize="large" />
              </IconButton>
            </Paper>
          )
        : _.map(employee?.rows, (row, index) => (
            <Fade in={true} key={row._id || index} timeout={500}>
              <Paper
                elevation={3}
                sx={{
                  p: 3,
                  borderRadius: 4,
                  mb: 2,
                  background: 'linear-gradient(to bottom, #ffffff, #f7f9fc)',
                }}
              >
                <Box className="flex justify-between items-start mb-3">
                  <Box className="flex items-center">
                    <PersonIcon color="primary" sx={{ mr: 1 }} />
                    <Box>
                      <Typography
                        variant="h6"
                        sx={{ fontWeight: 'bold', color: '#1976d2' }}
                      >
                        {row?.firstname} {row?.lastname}
                      </Typography>
                      <Box className="flex items-center">
                        <GroupsIcon
                          fontSize="small"
                          color="action"
                          sx={{ mr: 0.5 }}
                        />
                        <Typography variant="body1" color="textSecondary">
                          ทีม: {row?.team || '-'}
                        </Typography>
                      </Box>
                    </Box>
                  </Box>

                  <IconButton
                    onClick={handleRescan}
                    size="small"
                    sx={{
                      color: '#f44336',
                      bgcolor: '#ffebee',
                      '&:hover': { bgcolor: '#ffcdd2' },
                    }}
                  >
                    <CloseIcon />
                  </IconButton>
                </Box>

                <Divider sx={{ mb: 2 }} />

                {renderImage()}

                {imgSrc && (
                  <Box className="flex justify-center mt-2">
                    {project?.time_tracking_enabled ? (
                      <Button
                        variant="contained"
                        size="large"
                        onClick={() => onSubmit(row)}
                        startIcon={<SaveIcon />}
                        sx={{
                          borderRadius: 3,
                          py: 1,
                          px: 4,
                          boxShadow: 2,
                          background:
                            'linear-gradient(45deg, #43a047 30%, #66bb6a 90%)',
                        }}
                      >
                        บันทึกข้อมูล
                      </Button>
                    ) : (
                      <div>ไม่อยู่ในช่วงเวลาที่สามารถบันทึกได้</div>
                    )}
                  </Box>
                )}
              </Paper>
            </Fade>
          ))}
    </Container>
  );

  return (
    <Box className="min-h-screen bg-gradient-to-b from-blue-50 to-blue-100">
      {loading ? (
        <Loading loading />
      ) : (
        <Box className="flex flex-col">
          {renderFormEmployee()}
          {renderEmployeeList()}
        </Box>
      )}
    </Box>
  );
}
